import{_ as a,o,c as r,a2 as n}from"./chunks/framework.ByXR59UU.js";const f=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/faq/index.md","filePath":"openshield-xdp/faq/index.md","lastUpdated":1782412920000}'),t={name:"openshield-xdp/faq/index.md"};function i(s,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-kernel-version" tabindex="-1">What kernel version? <a class="header-anchor" href="#what-kernel-version" aria-label="Permalink to &quot;What kernel version?&quot;">​</a></h2><p>Linux ≥ 5.8. ≥ 5.11 for freplace.</p><h2 id="does-this-replace-iptables" tabindex="-1">Does this replace iptables? <a class="header-anchor" href="#does-this-replace-iptables" aria-label="Permalink to &quot;Does this replace iptables?&quot;">​</a></h2><p>No. XDP layer (before skb allocation) vs Netfilter (much later). Complementary.</p><h2 id="performance-overhead" tabindex="-1">Performance overhead? <a class="header-anchor" href="#performance-overhead" aria-label="Permalink to &quot;Performance overhead?&quot;">​</a></h2><p>~300–500 ns normal. ~1–2 μs under attack. ~50–70% single-core at 10M PPS.</p><h2 id="can-synproxy-break-connections" tabindex="-1">Can SYNPROXY break connections? <a class="header-anchor" href="#can-synproxy-break-connections" aria-label="Permalink to &quot;Can SYNPROXY break connections?&quot;">​</a></h2><p>Off by default. When enabled, only intercepts SYN + ACK. Kernel completes real handshake once cookie verified.</p><h2 id="hardware-offload" tabindex="-1">Hardware offload? <a class="header-anchor" href="#hardware-offload" aria-label="Permalink to &quot;Hardware offload?&quot;">​</a></h2><p><code>xdp_mode: auto</code> tries offload → native → generic. Requires smart NIC.</p><h2 id="tui-stuck-at-loading" tabindex="-1">TUI stuck at Loading? <a class="header-anchor" href="#tui-stuck-at-loading" aria-label="Permalink to &quot;TUI stuck at Loading?&quot;">​</a></h2><p><code>sudo openshield fix &amp;&amp; sudo openshield load</code></p><h2 id="verifier-fails-on-some-kernels" tabindex="-1">Verifier fails on some kernels? <a class="header-anchor" href="#verifier-fails-on-some-kernels" aria-label="Permalink to &quot;Verifier fails on some kernels?&quot;">​</a></h2><p>Run <code>sudo openshield fix</code>. Stale pins from old versions are the most common cause.</p>',15)])])}const m=a(t,[["render",i]]);export{f as __pageData,m as default};
